SELECT month, year, total_market_share
FROM browser_market_share
ORDER BY year DESC, month DESC;

SELECT browser_name
FROM browsers
ORDER BY market_position DESC;

SELECT AVG(chrome) AS average_chrome_market_share, year
FROM browser_market_share
GROUP BY year;

SELECT month, total_market_share
FROM browser_market_share
ORDER BY total_market_share DESC;

SELECT total_market_share
FROM browser_market_share
WHERE year = (SELECT MAX(year) FROM browser_market_share);

SELECT AVG(chrome) AS avg_chrome_market_share
FROM browser_market_share
WHERE region = 'North America' AND device_type = 'desktop';

SELECT 'Chrome' AS browser_name, chrome AS total_chrome_market_share
FROM browser_market_share
WHERE chrome > 10;
